// Test stackalloc Span<nint> and Span<nuint>

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");

// stackalloc Span<nint>
Span<nint> signedSpan = stackalloc nint[5];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = (nint)(i * 10);

Console.Write("Span<nint>:  ");
foreach (var v in signedSpan)
    Console.Write($"{v} ");
Console.WriteLine();

// stackalloc Span<nuint>
Span<nuint> unsignedSpan = stackalloc nuint[5];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i * 100);

Console.Write("Span<nuint>: ");
foreach (var v in unsignedSpan)
    Console.Write($"{v} ");
Console.WriteLine();

Console.WriteLine("Success — stackalloc with nint/nuint works!");

